module RefModule(
    input enable,           // Enable signal for the decoder.
    input [1:0] binary_in,  // Binary input data with a data width of 2 bits.
    output [3:0] one_hot_out // One-hot encoded output data with a data width of 4 bits.
);

reg [3:0] unused_decoded;         // Decoded output register.

always @(*)
    if (enable)
        case (binary_in)
            2'b00: unused_decoded = 4'b0001;
            2'b01: unused_decoded = 4'b0010;
            2'b10: unused_decoded = 4'b0100;
            2'b11: unused_decoded = 4'b1000;
            default: unused_decoded = 4'b0000;
        endcase
    else
        unused_decoded = 4'b0000;                        // All outputs are zero if enable is not active.

assign one_hot_out = unused_decoded;                    // Output unused_decoded value.

endmodule
